#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Contents.Enemies;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.humanoidAnimation)]
    public class HumanoidAnimationBehaviour : EnemyAnimationBehaviour
    {
        public HumanoidAnimationBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void UpdateAnimationParameters(Entity entity, int state)
        {
            var parameters = new AnimationParameters()
            {
                dead = false,
                walkState = WALK_STATE_NONE,
                armState = ARM_STATE_IDLE,
                specialState = 0
            };
            switch (state)
            {
                case STATE_WALK:
                case STATE_LEAVE:
                    parameters.walkState = WALK_STATE_WALK;
                    break;
                case STATE_MELEE_ATTACK:
                    parameters.armState = ARM_STATE_ATTACK;
                    break;
                case STATE_CAST:
                    parameters.armState = ARM_STATE_CAST;
                    break;
                case STATE_DEATH:
                    parameters.dead = true;
                    break;
                case STATE_RANGED_ATTACK:
                    parameters.armState = ARM_STATE_NONE;
                    break;
            }
            ModifyAnimationParameters(entity, state, ref parameters);
            entity.SetAnimationBool("Dead", parameters.dead);
            entity.SetAnimationInt("WalkState", parameters.walkState);
            entity.SetAnimationInt("ArmState", parameters.armState);
            entity.SetAnimationInt("SpecialState", parameters.specialState);
        }
        protected virtual void ModifyAnimationParameters(Entity entity, int state, ref AnimationParameters parameters)
        {
            if (ParatroopBuff.IsParachuting(entity))
            {
                parameters.armState = ARM_STATE_HANDS_UP;
            }
            var horse = entity.GetRidingEntity();
            var hasHorse = horse.ExistsAndAlive();
            if (hasHorse)
            {
                parameters.walkState = WALK_STATE_SIT;
            }
        }
        public const int WALK_STATE_NONE = 0;
        public const int WALK_STATE_WALK = 1;
        public const int WALK_STATE_SIT = 2;
        public const int ARM_STATE_NONE = 0;
        public const int ARM_STATE_IDLE = 1;
        public const int ARM_STATE_ATTACK = 2;
        public const int ARM_STATE_CAST = 3;
        public const int ARM_STATE_HANDS_UP = 4;
        public struct AnimationParameters
        {
            public bool dead;
            public int walkState;
            public int armState;
            public int specialState;
        }
    }
}